def dashboard_load_html(load1, load5, load15, cpu_count, host_present=True):
    """Render a fixed-width Load 1/5/15 pill for stable dashboard alignment."""
    if not host_present:
        return '<span class="metric-pill metric-unknown dashboard-load-pill" title="Host load is not reported">-</span>'

    values = f"{float(load1 or 0):.2f} / {float(load5 or 0):.2f} / {float(load15 or 0):.2f}"
    cores = max(0, safe_int(cpu_count, 0))
    if cores <= 0:
        return (
            '<span class="metric-pill metric-unknown dashboard-load-pill" '
            'title="CPU core count is missing in this retained snapshot">'
            f'{values}</span>'
        )

    load_pct = max(0.0, float(load1 or 0) * 100.0 / float(cores))
    if load_pct < 60.0:
        level = "ok"
    elif load_pct < 90.0:
        level = "warn"
    else:
        level = "crit"

    return (
        f'<span class="metric-pill metric-{level} dashboard-load-pill" '
        f'title="Load1 {load_pct:.1f}% of {cores} CPU cores; green &lt;60%, orange 60-&lt;90%, red ≥90%">'
        f'{values}</span>'
    )


def node_table(rows, sort_by="node", order="asc"):
    period = clean_period(request.args.get("period", "5m"))
    q = (request.args.get("q") or "").strip()
    body = ""
    total_nodes = len(rows)
    total_vms = sum(int(row[4] or 0) for row in rows)
    total_public = total_private = total_all = 0.0

    for row in rows:
        (
            node, live_last_seen, selected_bucket, retention_tier, vm_count, iface_count,
            public_total, private_total, node_total,
            public_packets, private_packets, public_interval, private_interval,
            node_packets, node_interval, net_drops, net_errors,
            host_present, load1, load5, load15, cpu_count, cpu_percent, ram_percent,
            disk_read_bps, disk_write_bps, uptime_seconds,
            net_source, public_ifaces, private_ifaces,
            public_pps_sort, private_pps_sort, node_pps_sort,
            public_ipv4, private_ipv4,
        ) = row
        total_public += float(public_total or 0)
        total_private += float(private_total or 0)
        total_all += float(node_total or 0)
        _row_at = (request.args.get("at") or "").strip()
        href = url_for("node_page", node=node, period=period, **({"at": _row_at} if _row_at else {}))
        source = str(net_source or "-")
        source_cls = "active" if source == "NIC" else ("yellow" if source in ("MIXED", "VM") else "stale")
        iface_note = ""
        if source in ("NIC", "MIXED"):
            iface_note = f'<small title="Public {escape(str(public_ifaces or "-"), quote=True)} · Private {escape(str(private_ifaces or "-"), quote=True)}">pub {escape(str(public_ifaces or "-"))} · pri {escape(str(private_ifaces or "-"))}</small>'
        elif source == "VM":
            source = "VM TAP"
            iface_note = '<small class="metric-subline">physical uplink sample unavailable</small>'
        load_html = dashboard_load_html(load1, load5, load15, cpu_count, host_present=bool(host_present))
        cpu_html = fmt_percent(cpu_percent) if host_present else "-"
        ram_html = fmt_percent(ram_percent) if host_present else "-"
        disk_r_html = human_rate(disk_read_bps) if host_present else "-"
        disk_w_html = human_rate(disk_write_bps) if host_present else "-"
        public_pps = float(public_packets or 0) / max(1.0, float(public_interval or CACHE_BUCKET_SECONDS))
        private_pps = float(private_packets or 0) / max(1.0, float(private_interval or CACHE_BUCKET_SECONDS))

        body += f"""
        <tr>
            <td>
                <div class="node-name-cell">
                    <a href="{escape(href, quote=True)}"><b>{escape(node)}</b></a>
                    {f'<small class="node-ipv4" title="Public IPv4">{escape(compact_ipv4(public_ipv4))}</small>' if public_ipv4 else ''}
                </div>
            </td>
            <td>{status_badge(live_last_seen)}</td>
            <td class="mono">{fmt_full(selected_bucket)}</td>
            <td class="num">{int(vm_count or 0)}</td>
            <td class="num dashboard-load-col" title="Host load average captured at the displayed snapshot">{load_html}</td>
            <td class="num">{fmt_uptime(uptime_seconds) if host_present else '-'}</td>
            <td class="num">{cpu_html}</td>
            <td class="num">{ram_html}</td>
            <td class="num">{fmt_pps_value(public_pps)}</td>
            <td class="num">{fmt_pps_value(private_pps)}</td>
            <td class="num"><b>{human(public_total)}</b></td>
            <td class="num"><b>{human(private_total)}</b></td>
            <td class="num"><b>{human(node_total)}</b></td>
            <td class="num">{disk_r_html}</td>
            <td class="num">{disk_w_html}</td>
            <td class="num">{int(net_drops or 0)}</td>
            <td class="num">{int(net_errors or 0)}</td>
            <td class="dashboard-interface-cell"><div class="dashboard-interface-wrap"><span class="vm-state {source_cls}">{escape(source)}</span>{iface_note}</div></td>
        </tr>
        """

    if not body:
        body = '<tr><td colspan="18" class="empty">No retained snapshot data</td></tr>'

    headers = {
        "node": node_sort_header("NODE", "node", period, q, sort_by, order),
        "status": node_sort_header("STATUS", "last_push", period, q, sort_by, order),
        "snapshot": node_sort_header("SNAPSHOT", "snapshot", period, q, sort_by, order),
        "vm": node_sort_header("VM", "vm", period, q, sort_by, order),
        "load": node_sort_header("LOAD 1/5/15", "load", period, q, sort_by, order),
        "uptime": node_sort_header("UPTIME", "uptime", period, q, sort_by, order),
        "cpu": node_sort_header("HOST CPU", "cpu", period, q, sort_by, order),
        "ram": node_sort_header("HOST RAM", "ram", period, q, sort_by, order),
        "pubpps": node_sort_header("PUBLIC PPS", "public_pps", period, q, sort_by, order),
        "pripps": node_sort_header("PRIVATE PPS", "private_pps", period, q, sort_by, order),
        "public": node_sort_header("PUBLIC", "public", period, q, sort_by, order),
        "private": node_sort_header("PRIVATE", "private", period, q, sort_by, order),
        "total": node_sort_header("TOTAL", "total", period, q, sort_by, order),
        "diskr": node_sort_header("DISK R/s", "diskr", period, q, sort_by, order),
        "diskw": node_sort_header("DISK W/s", "diskw", period, q, sort_by, order),
        "drops": node_sort_header("DROPS", "drops", period, q, sort_by, order),
        "errors": node_sort_header("ERR", "errors", period, q, sort_by, order),
        "source": node_sort_header("INTERFACE", "source", period, q, sort_by, order),
    }
    return f"""
    {V5054_DASHBOARD_CSS}
    <div class="card overview-card">
        <div class="overview-head"><h3>Exact Snapshot Summary</h3>
            <div class="overview-meta"><span>Nodes <b>{total_nodes}</b></span><span>VM <b>{total_vms}</b></span><span>Mode <b>one real push per node</b></span></div>
        </div>
        <div class="traffic-grid">
            <div class="traffic-box"><div class="traffic-title">Public</div><div class="traffic-total">{human(total_public)}</div></div>
            <div class="traffic-box"><div class="traffic-title">Private</div><div class="traffic-total">{human(total_private)}</div></div>
            <div class="traffic-box traffic-box-main"><div class="traffic-title">Total</div><div class="traffic-total">{human(total_all)}</div></div>
        </div>
    </div>
    <div class="card">
        <div class="table-title-row"><h3>Nodes</h3><div class="count-badges"><span>Sort <b>{escape(sort_by)} {escape(order)}</b></span><span>Status <b>live</b></span><span>Metrics <b>selected snapshot</b></span></div></div>
        <div class="table-wrap"><table class="node-dashboard-table"><thead><tr>
            <th>{headers['node']}</th><th>{headers['status']}</th><th>{headers['snapshot']}</th>
            <th>{headers['vm']}</th><th class="dashboard-load-col">{headers['load']}</th><th>{headers['uptime']}</th><th>{headers['cpu']}</th><th>{headers['ram']}</th>
            <th>{headers['pubpps']}</th><th>{headers['pripps']}</th><th>{headers['public']}</th><th>{headers['private']}</th><th>{headers['total']}</th>
            <th>{headers['diskr']}</th><th>{headers['diskw']}</th><th>{headers['drops']}</th><th>{headers['errors']}</th><th class="dashboard-interface-col">{headers['source']}</th>
        </tr></thead><tbody>{body}</tbody></table></div>
        <div class="table-hint">STATUS is live: Online with fewer than 2 missed pushes, Missed at exactly 2, Down after that. LOAD color uses Load1 / CPU cores: green below 60%, orange from 60% to below 90%, red at 90% or higher. LOAD 1/5/15 and every other metric come from the displayed SNAPSHOT. INTERFACE is shown last to keep the numeric columns aligned.</div>
    </div>
    """



def sort_header(label, key, node, period, q, current_sort, current_order, vm_status="active"):
    current_sort = clean_interface_sort(current_sort)
    current_order = clean_sort_order(current_order)
    next_order = reverse_order(current_order) if current_sort == key else "desc"
    arrow = ""
    if current_sort == key:
        arrow = " ↓" if current_order == "desc" else " ↑"
    net_mode = clean_node_net_mode(request.args.get("net", "both"))
    href = url_for(
        "node_page",
        node=node,
        period=period,
        q=q,
        sort=key,
        order=next_order,
        net=net_mode,
    )
    return f'<a class="sort-link" href="{escape(href, quote=True)}">{escape(label)}{arrow}</a>'


def interface_table(title, bridge, node, rows, period, q="", sort_by="total", order="desc", vm_status="active"):
    body = ""
    for (
        iface, vm_uuid, rx, tx, total, rx_packets, tx_packets, packets, drops, errors,
        avg_mbps, peak_mbps, avg_pps, peak_pps,
        sample_count, sample_expected, sample_max_gap_seconds, seconds_over_pps, seconds_over_mbps, sample_quality_rank,
        cpu_percent, vcpu_current, core_cpu_percent, ram_rss_kib, ram_current_kib,
        disk_read_bps, disk_write_bps, row_vm_status, last_push, vm_last_seen, interval_seconds,
    ) in rows:
        _row_at = (request.args.get("at") or "").strip()
        href = url_for("vm_page", node=node, vm_uuid=vm_uuid, bridge=bridge, iface=iface, period=period, **({"at": _row_at} if _row_at else {}))
        href_e = escape(href, quote=True)
        live = vm_live_status(vm_last_seen)
        row_status = clean_vm_status(row_vm_status)
        row_cls = "clickable stale-row" if (live == "stale" or row_status != "active") else "clickable"
        state_html = vm_status_badge(row_status, live)
        vm_uuid_e = escape(vm_uuid)
        quality = network_quality_from_rank(sample_quality_rank)
        sample_html = network_sample_badge(quality, sample_count, sample_expected, sample_max_gap_seconds)
        ram_pct = (float(ram_rss_kib or 0) * 100.0 / float(ram_current_kib or 1)) if ram_current_kib else 0.0
        ram_html = fmt_ram_pair(ram_rss_kib, ram_current_kib)
        if ram_current_kib:
            ram_html += f'<small class="metric-subline">{ram_pct:.1f}% RSS</small>'
        body += f"""
        <tr class="{row_cls}" onclick="if (!event.target.closest('a, button, input, select, textarea, label, form')) window.location='{href_e}'">
            <td>{state_html}</td>
            <td class="mono"><a href="{href_e}"><b>{escape(iface)}</b></a></td>
            <td class="mono"><span class="uuid-cell"><a href="{href_e}" title="{vm_uuid_e}">{vm_uuid_e}</a><button type="button" class="copy-btn" data-copy="{vm_uuid_e}" title="Copy UUID">⧉</button></span></td>
            <td class="num">{human(rx)}</td>
            <td class="num">{human(tx)}</td>
            <td class="num"><b>{human(total)}</b></td>
            <td class="num">{float(avg_mbps or 0):.2f}</td>
            <td class="num"><b>{float(peak_mbps or 0):.2f}</b></td>
            <td class="num">{fmt_pps_value(avg_pps)}</td>
            <td class="num"><b>{fmt_pps_value(peak_pps)}</b></td>
            <td class="num sample-cell">{sample_html}<small class="metric-subline">{int(seconds_over_pps or 0)}s PPS · {int(seconds_over_mbps or 0)}s Mbps</small></td>
            <td class="num"><b>{fmt_vm_cpu(cpu_percent, vcpu_current)}</b><small class="metric-subline">{float(cpu_percent or 0):.1f}% full</small></td>
            <td class="num">{int(vcpu_current or 0)}</td>
            <td class="num ram-cell">{ram_html}</td>
            <td class="num">{human_rate(disk_read_bps)}</td>
            <td class="num">{human_rate(disk_write_bps)}</td>
            <td class="num">{int(drops or 0)}</td>
            <td class="num">{int(errors or 0)}</td>
        </tr>"""
    if not body:
        body = '<tr><td colspan="18" class="empty">No data in this selected snapshot</td></tr>'

    hs = {
        "rx": sort_header("RX", "rx", node, period, q, sort_by, order, vm_status),
        "tx": sort_header("TX", "tx", node, period, q, sort_by, order, vm_status),
        "total": sort_header("TOTAL", "total", node, period, q, sort_by, order, vm_status),
        "mbps": sort_header("AVG Mbps", "mbps", node, period, q, sort_by, order, vm_status),
        "peakmbps": sort_header("PEAK Mbps", "peakmbps", node, period, q, sort_by, order, vm_status),
        "pps": sort_header("AVG PPS", "pps", node, period, q, sort_by, order, vm_status),
        "peakpps": sort_header("PEAK PPS", "peakpps", node, period, q, sort_by, order, vm_status),
        "sample": sort_header("SAMPLE", "sample", node, period, q, sort_by, order, vm_status),
        "cpu": sort_header("CPU Core%", "cpu", node, period, q, sort_by, order, vm_status),
        "vcpu": sort_header("vCPU", "vcpu", node, period, q, sort_by, order, vm_status),
        "ram": sort_header("RAM RSS / Assigned", "ram", node, period, q, sort_by, order, vm_status),
        "diskr": sort_header("DISK R/s", "diskr", node, period, q, sort_by, order, vm_status),
        "diskw": sort_header("DISK W/s", "diskw", node, period, q, sort_by, order, vm_status),
        "drops": sort_header("DROPS", "drops", node, period, q, sort_by, order, vm_status),
        "errors": sort_header("ERR", "errors", node, period, q, sort_by, order, vm_status),
    }
    return f"""
    <div class="card vm-table-card">
        <div class="table-title-row">
            <h3>{escape(title)}</h3>
            <div class="count-badges"><span>VM rows <b>{len(rows)}</b></span><span>Snapshot <b>exact</b></span></div>
        </div>
        <div class="table-wrap">
        <table class="table-vm">
            <colgroup>
                <col class="col-state"><col class="col-iface"><col class="col-uuid">
                <col class="col-rx"><col class="col-tx"><col class="col-total">
                <col class="col-mbps"><col class="col-peakmbps"><col class="col-pps"><col class="col-peakpps">
                <col class="col-sample"><col class="col-cpu"><col class="col-vcpu"><col class="col-ram">
                <col class="col-diskr"><col class="col-diskw"><col class="col-drops"><col class="col-errors">
            </colgroup>
            <thead><tr>
                <th>STATE</th><th>INTERFACE</th><th>VM UUID</th>
                <th class="num-head">{hs['rx']}</th><th class="num-head">{hs['tx']}</th><th class="num-head">{hs['total']}</th>
                <th class="num-head">{hs['mbps']}</th><th class="num-head">{hs['peakmbps']}</th>
                <th class="num-head">{hs['pps']}</th><th class="num-head">{hs['peakpps']}</th><th class="num-head">{hs['sample']}</th>
                <th class="num-head">{hs['cpu']}</th><th class="num-head">{hs['vcpu']}</th><th class="num-head">{hs['ram']}</th>
                <th class="num-head">{hs['diskr']}</th><th class="num-head">{hs['diskw']}</th><th class="num-head">{hs['drops']}</th><th class="num-head">{hs['errors']}</th>
            </tr></thead>
            <tbody>{body}</tbody>
        </table>
        </div>
        <div class="table-hint">CPU Core% uses 100% per fully used vCPU. The smaller “full” value is utilization across all assigned vCPUs. RAM is RSS / assigned memory.</div>
    </div>"""

def get_node_physical_nic_period(node, period):
    """Return physical-NIC snapshot plus current br0/br1 addresses."""
    period = clean_period(period)
    conn = db()
    try:
        result = {}

        # IPs are current node configuration. They are stored independently from
        # historical counter snapshots because the address belongs to br0/br1.
        address_rows = conn.execute("""
            SELECT role, bridge, last_seen, primary_ipv4,
                   ipv4_json, operstate, carrier, mtu, mac
            FROM node_bridge_addresses_latest
            WHERE node=?
            ORDER BY CASE role WHEN 'public' THEN 1 WHEN 'private' THEN 2 ELSE 9 END, role
        """, (node,)).fetchall()

        for (role, bridge, address_seen, primary_ipv4,
             ipv4_json, operstate, carrier, mtu, mac) in address_rows:
            key = str(role or "").lower()
            result[key] = {
                "role": key,
                "bridge": bridge or "-",
                "iface": "-",
                "rx_mbps": 0.0,
                "tx_mbps": 0.0,
                "rx_pps": 0.0,
                "tx_pps": 0.0,
                "last_seen": int(address_seen or 0),
                "samples": 0,
                "covered_seconds": 0,
                "source": "bridge address",
                "ipv4": decode_ip_json(ipv4_json),
                "primary_ipv4": primary_ipv4 or "",
                "operstate": operstate or "-",
                "carrier": int(carrier or 0),
                "mtu": int(mtu or 0),
                "bridge_mac": normalize_mac_address(mac),
                "mac": "",
            }

        physical_identity_rows = conn.execute("""
            SELECT role,bridge,iface,mac,last_seen
              FROM node_physical_net_latest
             WHERE node=?
             ORDER BY CASE role WHEN 'public' THEN 1 WHEN 'private' THEN 2 ELSE 9 END,role
        """, (node,)).fetchall()
        for role, bridge, iface, mac, identity_seen in physical_identity_rows:
            key = str(role or "").lower()
            current = result.setdefault(key, {
                "role": key,
                "ipv4": [],
                "primary_ipv4": "",
                "operstate": "-",
                "carrier": 0,
                "mtu": 0,
                "bridge_mac": "",
            })
            current["bridge"] = bridge or current.get("bridge") or "-"
            current["iface"] = iface or current.get("iface") or "-"
            current["mac"] = normalize_mac_address(mac)
            current["identity_seen"] = int(identity_seen or 0)

        selected_bucket, _latest_bucket = resolve_snapshot_bucket(conn, period, node=node)
        nic_bucket = resolve_table_snapshot_bucket(conn, "node_physical_net_stats", node, selected_bucket)
        if not nic_bucket:
            return result

        rows = conn.execute("""
            SELECT
                role,
                MAX(bridge) AS bridge,
                MAX(iface) AS iface,
                SUM(COALESCE(rx_delta, 0)) AS rx_delta,
                SUM(COALESCE(tx_delta, 0)) AS tx_delta,
                SUM(COALESCE(rx_packets_delta, 0)) AS rx_packets_delta,
                SUM(COALESCE(tx_packets_delta, 0)) AS tx_packets_delta,
                MAX(COALESCE(interval_seconds, ?)) AS interval_seconds,
                MAX(time) AS last_seen
            FROM node_physical_net_stats
            WHERE node=? AND bucket=?
            GROUP BY role
            ORDER BY CASE role WHEN 'public' THEN 1 WHEN 'private' THEN 2 ELSE 9 END, role
        """, (CACHE_BUCKET_SECONDS, node, nic_bucket)).fetchall()

        for role, bridge, iface, rx_delta, tx_delta, rx_packets, tx_packets, interval_seconds, last_seen in rows:
            key = str(role or "").lower()
            interval = max(1, int(interval_seconds or CACHE_BUCKET_SECONDS))
            current = result.setdefault(key, {
                "role": key,
                "ipv4": [],
                "primary_ipv4": "",
                "operstate": "-",
                "carrier": 0,
                "mtu": 0,
                "bridge_mac": "",
                "mac": "",
            })
            current.update({
                "bridge": bridge or current.get("bridge") or "-",
                "iface": iface or "-",
                "rx_mbps": float(rx_delta or 0) * 8.0 / interval / 1_000_000.0,
                "tx_mbps": float(tx_delta or 0) * 8.0 / interval / 1_000_000.0,
                "rx_pps": float(rx_packets or 0) / interval,
                "tx_pps": float(tx_packets or 0) / interval,
                "last_seen": int(last_seen or nic_bucket),
                "samples": 1,
                "covered_seconds": interval,
                "source": "exact snapshot",
            })
        return result
    finally:
        conn.close()


def node_nic_badges(node, period):
    data = get_node_physical_nic_period(node, period)

    def badge(role, default_bridge):
        r = data.get(role)
        if r:
            bridge = r.get("bridge") or default_bridge
            iface = r.get("iface") or "-"
            label = f"{bridge} / {iface}"
            total_pps = float(r.get("rx_pps") or 0) + float(r.get("tx_pps") or 0)
            ipv4 = ", ".join(r.get("ipv4") or []) or "not assigned"
            traffic = (
                f"RX {float(r.get('rx_mbps') or 0):.2f} Mbps · "
                f"TX {float(r.get('tx_mbps') or 0):.2f} Mbps · "
                f"PPS {fmt_pps_value(total_pps)} · "
                f"snapshot {fmt_push(r.get('last_seen'))}"
            )
            address_detail = f"Current IPv4 {ipv4}"
            physical_mac = normalize_mac_address(r.get("mac")) or "not reported"
            return (
                f'<span class="nic-badge"><b>{role.title()}</b> '
                f'{escape(label)}<small class="nic-address">{escape(address_detail)}</small>'
                f'<small class="nic-address">Physical MAC {escape(physical_mac)}</small>'
                f'<small>{escape(traffic)}</small></span>'
            )
        return (
            f'<span class="nic-badge"><b>{role.title()}</b> '
            f'{escape(default_bridge)} / no data '
            f'<small>Agent has not reported bridge addresses yet</small></span>'
        )

    return f'<div class="nic-map">{badge("public", PUBLIC_BRIDGE)}{badge("private", PRIVATE_BRIDGE)}</div>'


def overview_cards(row, node, period):
    (vm_count, iface_count, pub_rx, pub_tx, pub_total, pri_rx, pri_tx, pri_total,
     node_rx, node_tx, node_total, node_packets, node_drops, node_errors,
     last_push, interval_seconds) = row
    live_last_seen = get_node_live_last_seen(node)
    tier = get_snapshot_tier(node, last_push)
    return f"""
    <div class="card overview-card">
        <div class="overview-head">
            <h3>Overview</h3>
            <div class="overview-meta">
                <span>Live {status_badge(live_last_seen)}</span>
                <span>Snapshot <b>{fmt_full(last_push)}</b></span>
                <span>Resolution <b>{escape(tier)}</b></span>
                <span>VM <b>{vm_count or 0}</b></span>
                <span>Interfaces <b>{iface_count or 0}</b></span>
                <span>PPS <b>{fmt_pps(node_packets, interval_seconds)}</b></span>
                <span>Drops <b>{int(node_drops or 0)}</b></span>
                <span>Err <b>{int(node_errors or 0)}</b></span>
            </div>
        </div>
        {node_nic_badges(node, period)}
        <div class="traffic-grid">
            <div class="traffic-box"><div class="traffic-title">Public</div><div class="traffic-total">{human(pub_total)}</div><div class="traffic-split"><span>RX <b>{human(pub_rx)}</b></span><span>TX <b>{human(pub_tx)}</b></span></div></div>
            <div class="traffic-box"><div class="traffic-title">Private</div><div class="traffic-total">{human(pri_total)}</div><div class="traffic-split"><span>RX <b>{human(pri_rx)}</b></span><span>TX <b>{human(pri_tx)}</b></span></div></div>
            <div class="traffic-box traffic-box-main"><div class="traffic-title">Node</div><div class="traffic-total">{human(node_total)}</div><div class="traffic-split"><span>RX <b>{human(node_rx)}</b></span><span>TX <b>{human(node_tx)}</b></span></div></div>
        </div>
        <div class="table-hint">Status uses the newest heartbeat. Counters and rates use one retained real push only.</div>
    </div>
    """


def chart_step_seconds(period):
    """Expected native resolution. Queries now return retained real buckets only."""
    period = clean_period(period)
    return CACHE_BUCKET_SECONDS if period_seconds(period) <= RAW_RETENTION_DAYS * 86400 else 3600



def fmt_chart_label(ts, step):
    dt = datetime.fromtimestamp(int(ts), TZ)
    if step >= 86400:
        return dt.strftime("%m-%d")
    if step >= 3600:
        return dt.strftime("%m-%d %H:%M")
    return dt.strftime("%H:%M")


def vm_period_links(current, node, vm_uuid, bridge, iface):
    links = []
    for period in PERIODS:
        href = url_for(
            "vm_page",
            node=node,
            vm_uuid=vm_uuid,
            bridge=bridge,
            iface=iface,
            period=period,
        )
        cls = "active" if period == current else ""
        links.append(f'<a class="{cls}" href="{escape(href, quote=True)}">{escape(period_label(period))}</a>')
    return "".join(links)


def query_vm_chart(node, vm_uuid, period, bridge="", iface=""):
    """Return exact retained VM network buckets with whole-window averages and local peaks."""
    start, end = range_for_period(period)
    params = [node, vm_uuid, start, end]
    extra_sql = ""
    if bridge:
        extra_sql += " AND bridge=?"; params.append(bridge)
    if iface:
        extra_sql += " AND iface=?"; params.append(iface)
    conn = db()
    try:
        raw_rows = conn.execute(f"""
            SELECT bucket,
                   SUM(MAX(rx_delta,0)), SUM(MAX(tx_delta,0)), SUM(MAX(rx_delta,0)+MAX(tx_delta,0)),
                   SUM(MAX(rx_packets_delta,0)), SUM(MAX(tx_packets_delta,0)),
                   SUM(MAX(rx_drop_delta,0)), SUM(MAX(tx_drop_delta,0)),
                   SUM(MAX(rx_error_delta,0)), SUM(MAX(tx_error_delta,0)),
                   MAX(last_push), MAX(COALESCE(interval_seconds,?)),
                   MAX(COALESCE(rx_mbps_peak,0)), MAX(COALESCE(tx_mbps_peak,0)),
                   MAX(COALESCE(rx_pps_peak,0)), MAX(COALESCE(tx_pps_peak,0)),
                   SUM(COALESCE(network_sample_count,0)), SUM(COALESCE(network_sample_expected,0)),
                   MAX(COALESCE(network_sample_max_gap_seconds,0)),
                   SUM(COALESCE(seconds_over_pps,0)), SUM(COALESCE(seconds_over_mbps,0)),
                   MAX(CASE UPPER(COALESCE(network_sample_quality,'LEGACY')) WHEN 'POOR' THEN 3 WHEN 'DEGRADED' THEN 2 WHEN 'GOOD' THEN 1 ELSE 0 END)
            FROM node_stats
            WHERE node=? AND vm_uuid=? AND bucket>=? AND bucket<? {extra_sql}
            GROUP BY bucket ORDER BY bucket
        """, [CACHE_BUCKET_SECONDS] + params).fetchall()
    finally:
        conn.close()
    rows = []
    for r in raw_rows:
        interval = max(1, int(r[11] or CACHE_BUCKET_SECONDS))
        rx, tx = int(r[1] or 0), int(r[2] or 0)
        rxp, txp = int(r[4] or 0), int(r[5] or 0)
        rxd, txd, rxe, txe = int(r[6] or 0), int(r[7] or 0), int(r[8] or 0), int(r[9] or 0)
        rows.append({
            "bucket": int(r[0]), "label": fmt_chart_label(r[0], interval),
            "rx": rx, "tx": tx, "total": int(r[3] or 0),
            "rx_mbps": rx*8.0/interval/1000000.0, "tx_mbps": tx*8.0/interval/1000000.0,
            "mbps": (rx+tx)*8.0/interval/1000000.0,
            "rx_mbps_peak": float(r[12] or 0), "tx_mbps_peak": float(r[13] or 0),
            "peak_mbps": max(float(r[12] or 0), float(r[13] or 0)),
            "rx_packets": rxp, "tx_packets": txp, "packets": rxp+txp,
            "rx_pps": rxp/interval, "tx_pps": txp/interval, "pps": (rxp+txp)/interval,
            "rx_pps_peak": float(r[14] or 0), "tx_pps_peak": float(r[15] or 0),
            "peak_pps": max(float(r[14] or 0), float(r[15] or 0)),
            "rx_packet_size_avg": rx/float(rxp) if rxp else 0.0,
            "tx_packet_size_avg": tx/float(txp) if txp else 0.0,
            "sample_count": int(r[16] or 0), "sample_expected": int(r[17] or 0),
            "sample_max_gap_seconds": float(r[18] or 0),
            "seconds_over_pps": int(r[19] or 0), "seconds_over_mbps": int(r[20] or 0),
            "sample_quality": network_quality_from_rank(r[21]),
            "rx_drops": rxd, "tx_drops": txd, "drops": rxd+txd,
            "rx_errors": rxe, "tx_errors": txe, "errors": rxe+txe,
            "last_push": int(r[10] or 0), "interval_seconds": interval,
        })
    gaps = [rows[i]["bucket"]-rows[i-1]["bucket"] for i in range(1, len(rows)) if rows[i]["bucket"]>rows[i-1]["bucket"]]
    step = min(gaps) if gaps else chart_step_seconds(period)
    return rows, start, end, step



NODE_CHART_MAX_POINTS = max(60, min(480, int(os.environ.get("BW_NODE_CHART_MAX_POINTS", "240"))))


def _node_retained_buckets(conn, node, period):
    """Return real retained buckets in the requested range from the compact index.

    Falling back to node_stats keeps pre-index installations readable. This query
    touches one compact row per push, not every VM row in the period.
    """
    start, end = range_for_period(period)
    rows = conn.execute(
        """
        SELECT bucket
        FROM node_push_snapshots
        WHERE node=? AND bucket>=? AND bucket<?
        ORDER BY bucket
        """,
        (node, start, end),
    ).fetchall()
    if not rows:
        rows = conn.execute(
            """
            SELECT DISTINCT bucket
            FROM node_stats
            WHERE node=? AND bucket>=? AND bucket<?
            ORDER BY bucket
            """,
            (node, start, end),
        ).fetchall()
    return [int(row[0]) for row in rows if row and int(row[0] or 0) > 0]


def _sample_real_buckets(bucket_ids, max_points=NODE_CHART_MAX_POINTS):
    """Evenly select real push buckets without averaging or inventing zeroes."""
    ids = list(dict.fromkeys(int(v) for v in bucket_ids if int(v or 0) > 0))
    if len(ids) <= max_points:
        return ids
    if max_points <= 1:
        return [ids[-1]]
    chosen = []
    last_index = len(ids) - 1
    for i in range(max_points):
        idx = round(i * last_index / (max_points - 1))
        value = ids[idx]
        if not chosen or chosen[-1] != value:
            chosen.append(value)
    return chosen


def _sql_in_placeholders(values):
    return ",".join("?" for _ in values) or "NULL"


def query_node_chart(node, period, q="", vm_status="active"):
    """Return at most NODE_CHART_MAX_POINTS real node buckets.

    The old implementation grouped every VM row in the legacy long-range window for
    several charts, which could make /node pages time out. This version first
    samples real retained push buckets from node_push_snapshots, then reads only
    those buckets. No value is averaged and no fake zero bucket is created.
    """
    start, end = range_for_period(period)
    conn = db()
    try:
        bucket_ids = _sample_real_buckets(_node_retained_buckets(conn, node, period))
        if not bucket_ids:
            return [], start, end, chart_step_seconds(period)
        placeholders = _sql_in_placeholders(bucket_ids)
        params = [PUBLIC_BRIDGE, PRIVATE_BRIDGE, node] + bucket_ids
        search_sql = ""
        if q:
            search_sql = " AND (ns.vm_uuid LIKE ? OR ns.iface LIKE ? OR ns.node LIKE ?)"
            p = like_pattern(q)
            params.extend([p, p, p])
        raw_rows = conn.execute(f"""
            SELECT
                ns.bucket,
                SUM(CASE WHEN ns.bridge=? THEN ns.rx_delta+ns.tx_delta ELSE 0 END),
                SUM(CASE WHEN ns.bridge=? THEN ns.rx_delta+ns.tx_delta ELSE 0 END),
                SUM(ns.rx_delta), SUM(ns.tx_delta), SUM(ns.rx_delta+ns.tx_delta),
                MAX(ns.last_push)
            FROM node_stats ns
            LEFT JOIN vm_inventory vi ON vi.node=ns.node AND vi.vm_uuid=ns.vm_uuid
            WHERE ns.node=? AND ns.bucket IN ({placeholders})
              AND COALESCE(vi.status, 'active')!='hidden'
              {search_sql}
            GROUP BY ns.bucket
            ORDER BY ns.bucket
        """, params).fetchall()
    finally:
        conn.close()
    rows = [{
        "bucket": int(r[0]), "label": fmt_chart_label(r[0], CACHE_BUCKET_SECONDS),
        "public": int(r[1] or 0), "private": int(r[2] or 0),
        "rx": int(r[3] or 0), "tx": int(r[4] or 0), "total": int(r[5] or 0),
        "last_push": int(r[6] or 0),
    } for r in raw_rows]
    gaps = [rows[i]["bucket"] - rows[i-1]["bucket"] for i in range(1, len(rows))]
    step = min((g for g in gaps if g > 0), default=chart_step_seconds(period))
    return rows, start, end, step


def sample_chart_rows(rows, max_points=360):
    rows = list(rows or [])
    if len(rows) <= max_points:
        return rows
    stride = max(1, int(math.ceil(len(rows) / float(max_points))))
    sampled = rows[::stride]
    if rows and sampled[-1] is not rows[-1]:
        sampled.append(rows[-1])
    return sampled


def node_chart_svg(rows, title):
    rows = sample_chart_rows(rows)
    # Keep the node chart clean: show Public and Private only.
    # Total remains available in the overview cards and the raw data table below.
    if not rows or max((max(r["public"], r["private"]) for r in rows), default=0) <= 0:
        return f"""
        <div class="card chart-card node-chart-card">
            <h3>{escape(title)}</h3>
            <div class="empty">No chart data in this period</div>
        </div>
        """

    w, h = 1100, 280
    left, right, top, bottom = 74, 18, 18, 42
    plot_w = w - left - right
    plot_h = h - top - bottom
    real_max = max(max(r["public"], r["private"]) for r in rows) or 1
    max_v = nice_ceiling(real_max)

    grid = []
    labels = []
    for i in range(5):
        ratio = i / 4
        y = top + plot_h - ratio * plot_h
        value = max_v * ratio
        grid.append(f'<line x1="{left}" y1="{y:.1f}" x2="{w-right}" y2="{y:.1f}" class="grid-line"/>')
        labels.append(f'<text x="8" y="{y+4:.1f}" class="axis-label">{escape(human(value))}</text>')

    x_labels = []
    n = len(rows)
    if n <= 7:
        idxs = list(range(n))
    else:
        idxs = sorted(set([0, n//4, n//2, (3*n)//4, n-1]))
    for idx in idxs:
        x = left + (idx * plot_w / (n - 1)) if n > 1 else left + plot_w / 2
        x_labels.append(f'<text x="{x:.1f}" y="{h-15}" class="x-label" text-anchor="middle">{escape(rows[idx]["label"])}</text>')

    public_points = make_points(rows, "public", left, top, plot_w, plot_h, max_v)
    private_points = make_points(rows, "private", left, top, plot_w, plot_h, max_v)

    hover_items = []
    dot_items = []
    band_w = plot_w / max(n - 1, 1)
    for idx, row in enumerate(rows):
        x_public, y_public = point_xy(rows, idx, "public", left, top, plot_w, plot_h, max_v)
        x_private, y_private = point_xy(rows, idx, "private", left, top, plot_w, plot_h, max_v)
        if row["public"] or row["private"]:
            dot_items.append(f'<circle cx="{x_public:.1f}" cy="{y_public:.1f}" r="2.5" class="dot public-dot"/>')
            dot_items.append(f'<circle cx="{x_private:.1f}" cy="{y_private:.1f}" r="2.5" class="dot private-dot"/>')
        hover_x = x_public - band_w / 2
        hover_w = band_w if n > 1 else plot_w
        tooltip = (
            f"{fmt_full(row['bucket'])}\n"
            f"Public: {human(row['public'])}\n"
            f"Private: {human(row['private'])}\n"
            f"RX: {human(row['rx'])}\n"
            f"TX: {human(row['tx'])}\n"
            f"Total: {human(row['total'])}"
        )
        hover_items.append(
            f'<rect x="{hover_x:.1f}" y="{top}" width="{hover_w:.1f}" height="{plot_h}" class="hover-zone">'
            f'<title>{escape(tooltip)}</title></rect>'
        )

    return f"""
    <div class="card chart-card node-chart-card">
        <h3>{escape(title)}</h3>
        <div class="legend">
            <span><i class="public"></i>Public</span>
            <span><i class="private"></i>Private</span>
            <span class="chart-note">Total is shown in the raw data table below</span>
        </div>
        <div class="svg-wrap node-svg-wrap">
            <svg viewBox="0 0 {w} {h}" role="img" aria-label="{escape(title)}">
                {''.join(grid)}
                {''.join(labels)}
                <line x1="{left}" y1="{top}" x2="{left}" y2="{h-bottom}" class="axis"/>
                <line x1="{left}" y1="{h-bottom}" x2="{w-right}" y2="{h-bottom}" class="axis"/>
                <polyline points="{public_points}" class="line public-line"/>
                <polyline points="{private_points}" class="line private-line"/>
                {''.join(dot_items)}
                {''.join(x_labels)}
                {''.join(hover_items)}
            </svg>
        </div>
    </div>
    """


NODE_SNAPSHOT_ROWS_PER_PAGE = 50


def node_chart_raw_sort_header(label, key, node, period, q, current_sort, current_order, table_sort, table_order):
    current_sort = clean_node_chart_sort(current_sort)
    current_order = clean_sort_order(current_order)
    next_order = reverse_order(current_order) if current_sort == key else "desc"
    href = url_for(
        "node_page",
        node=node,
        period=period,
        q=q,
        sort=table_sort,
        order=table_order,
        chart_sort=key,
        chart_order=next_order,
        raw_page=1,
        raw_limit=NODE_SNAPSHOT_ROWS_PER_PAGE,
        net=clean_node_net_mode(request.args.get("net", "both")),
    ) + "#real-snapshot-samples"
    arrow = " ↓" if current_sort == key and current_order == "desc" else (" ↑" if current_sort == key else "")
    return f'<a class="sort-link" href="{escape(href, quote=True)}">{escape(label)}{arrow}</a>'


def node_chart_table(rows, node, period, q="", chart_sort="time", chart_order="desc", table_sort="total", table_order="desc"):
    chart_sort = clean_node_chart_sort(chart_sort)
    chart_order = clean_sort_order(chart_order)
    page_no = clean_page(request.args.get("raw_page", 1))
    limit = NODE_SNAPSHOT_ROWS_PER_PAGE

    key_map = {
        "time": lambda r: int(r["bucket"]),
        "public": lambda r: int(r["public"]),
        "private": lambda r: int(r["private"]),
        "rx": lambda r: int(r["rx"]),
        "tx": lambda r: int(r["tx"]),
        "total": lambda r: int(r["total"]),
    }
    all_rows = sorted(
        list(rows),
        key=key_map[chart_sort],
        reverse=(chart_order == "desc"),
    )

    total = len(all_rows)
    total_pages = max(1, int(math.ceil(total / float(limit))))
    page_no = min(page_no, total_pages)
    offset = (page_no - 1) * limit
    page_rows = all_rows[offset:offset + limit]

    body = "".join(
        f"<tr>"
        f"<td class='mono'>{fmt_full(r['bucket'])}</td>"
        f"<td>{human(r['public'])}</td>"
        f"<td>{human(r['private'])}</td>"
        f"<td>{human(r['rx'])}</td>"
        f"<td>{human(r['tx'])}</td>"
        f"<td><b>{human(r['total'])}</b></td>"
        f"</tr>"
        for r in page_rows
    )
    if not body:
        body = '<tr><td colspan="6" class="empty">No retained data in this period</td></tr>'

    headers = [
        node_chart_raw_sort_header(
            label,
            key,
            node,
            period,
            q,
            chart_sort,
            chart_order,
            table_sort,
            table_order,
        )
        for label, key in (
            ("TIME", "time"),
            ("PUBLIC", "public"),
            ("PRIVATE", "private"),
            ("RX", "rx"),
            ("TX", "tx"),
            ("TOTAL", "total"),
        )
    ]

    net_mode = clean_node_net_mode(request.args.get("net", "both"))

    def page_href(target):
        return url_for(
            "node_page",
            node=node,
            period=period,
            q=q,
            sort=table_sort,
            order=table_order,
            chart_sort=chart_sort,
            chart_order=chart_order,
            raw_page=target,
            raw_limit=limit,
            net=net_mode,
        ) + "#real-snapshot-samples"

    def page_link(label, target, active=False, disabled=False):
        if disabled:
            return f'<span class="page-link disabled">{escape(str(label))}</span>'
        cls = "page-link active" if active else "page-link"
        return f'<a class="{cls}" href="{escape(page_href(target), quote=True)}">{escape(str(label))}</a>'

    page_items = [
        page_link("Prev", max(1, page_no - 1), disabled=(page_no <= 1))
    ]
    page_set = {1, total_pages, page_no - 2, page_no - 1, page_no, page_no + 1, page_no + 2}
    page_set = sorted(p for p in page_set if 1 <= p <= total_pages)
    last_page = 0
    for target in page_set:
        if last_page and target - last_page > 1:
            page_items.append('<span class="page-gap">...</span>')
        page_items.append(page_link(target, target, active=(target == page_no)))
        last_page = target
    page_items.append(
        page_link("Next", min(total_pages, page_no + 1), disabled=(page_no >= total_pages))
    )

    start_row = 0 if total == 0 else offset + 1
    end_row = min(total, offset + limit)
    pager = f"""
    <div class="pagination">
        <div class="page-summary">
            Showing <b>{start_row}</b>-<b>{end_row}</b> of <b>{total}</b>
            · Page <b>{page_no}/{total_pages}</b>
        </div>
        <div class="page-links">{''.join(page_items)}</div>
    </div>
    """

    return f"""
    <div class="card node-chart-table" id="real-snapshot-samples">
        <div class="table-title-row">
            <h3>Real Snapshot Samples</h3>
            <div class="count-badges">
                <span>Displayed <b>{len(page_rows)}</b></span>
                <span>Total <b>{total}</b></span>
                <span>Rows/page <b>{limit}</b></span>
                <span>No averaging <b>enabled</b></span>
            </div>
        </div>
        <div class="table-wrap">
            <table>
                <thead><tr>{''.join(f'<th>{h}</th>' for h in headers)}</tr></thead>
                <tbody>{body}</tbody>
            </table>
        </div>
        {pager}
        <div class="table-hint">
            The table shows 50 real retained snapshots per page. For fast long-range pages,
            the app still selects at most {NODE_CHART_MAX_POINTS} real pushes; values are not averaged or zero-filled.
        </div>
    </div>
    """


def nice_ceiling(value):
    value = float(value or 0)
    if value <= 0:
        return 1
    exponent = math.floor(math.log10(value))
    fraction = value / (10 ** exponent)
    if fraction <= 1:
        nice = 1
    elif fraction <= 2:
        nice = 2
    elif fraction <= 5:
        nice = 5
    else:
        nice = 10
    return nice * (10 ** exponent)


def point_xy(rows, idx, key, x0, y0, plot_w, plot_h, max_v):
    if len(rows) == 1:
        x = x0 + plot_w / 2
    else:
        x = x0 + (idx * plot_w / (len(rows) - 1))
    y = y0 + plot_h - ((rows[idx][key] / max_v) * plot_h if max_v else 0)
    return x, y

def make_points(rows, key, x0, y0, plot_w, plot_h, max_v):
    if not rows:
        return ""
    if len(rows) == 1:
        x = x0 + plot_w / 2
        y = y0 + plot_h - ((rows[0][key] / max_v) * plot_h if max_v else 0)
        return f"{x:.1f},{y:.1f}"

    points = []
    for i, row in enumerate(rows):
        x = x0 + (i * plot_w / (len(rows) - 1))
        y = y0 + plot_h - ((row[key] / max_v) * plot_h if max_v else 0)
        points.append(f"{x:.1f},{y:.1f}")
    return " ".join(points)


def vm_chart_svg(rows, title):
    rows = sample_chart_rows(rows)
    if not rows or max((r["rx"] + r["tx"] for r in rows), default=0) <= 0:
        return f"""
        <div class="card chart-card small-chart">
            <h3>{escape(title)}</h3>
            <div class="empty">No chart data in this period</div>
        </div>
        """

    # Compact chart. VM page shows RX/TX only. The clicked row already defines scope.
    w, h = 860, 240
    left, right, top, bottom = 74, 18, 18, 42
    plot_w = w - left - right
    plot_h = h - top - bottom
    real_max = max(max(r["rx"], r["tx"]) for r in rows) or 1
    max_v = nice_ceiling(real_max)

    grid = []
    labels = []
    for i in range(5):
        ratio = i / 4
        y = top + plot_h - ratio * plot_h
        value = max_v * ratio
        grid.append(f'<line x1="{left}" y1="{y:.1f}" x2="{w-right}" y2="{y:.1f}" class="grid-line"/>')
        labels.append(f'<text x="8" y="{y+4:.1f}" class="axis-label">{escape(human(value))}</text>')

    x_labels = []
    n = len(rows)
    if n <= 7:
        idxs = list(range(n))
    else:
        idxs = sorted(set([0, n//4, n//2, (3*n)//4, n-1]))
    for idx in idxs:
        x = left + (idx * plot_w / (n - 1)) if n > 1 else left + plot_w / 2
        x_labels.append(f'<text x="{x:.1f}" y="{h-15}" class="x-label" text-anchor="middle">{escape(rows[idx]["label"])}</text>')

    rx_points = make_points(rows, "rx", left, top, plot_w, plot_h, max_v)
    tx_points = make_points(rows, "tx", left, top, plot_w, plot_h, max_v)

    hover_items = []
    dot_items = []
    band_w = plot_w / max(n - 1, 1)
    for idx, row in enumerate(rows):
        x_rx, y_rx = point_xy(rows, idx, "rx", left, top, plot_w, plot_h, max_v)
        x_tx, y_tx = point_xy(rows, idx, "tx", left, top, plot_w, plot_h, max_v)
        if row["rx"] or row["tx"]:
            dot_items.append(f'<circle cx="{x_rx:.1f}" cy="{y_rx:.1f}" r="2.5" class="dot rx-dot"/>')
            dot_items.append(f'<circle cx="{x_tx:.1f}" cy="{y_tx:.1f}" r="2.5" class="dot tx-dot"/>')
        hover_x = x_rx - band_w / 2
        hover_w = band_w if n > 1 else plot_w
        tooltip = (
            f"{fmt_full(row['bucket'])}\n"
            f"RX: {human(row['rx'])}\n"
            f"TX: {human(row['tx'])}"
        )
        hover_items.append(
            f'<rect x="{hover_x:.1f}" y="{top}" width="{hover_w:.1f}" height="{plot_h}" class="hover-zone">'
            f'<title>{escape(tooltip)}</title></rect>'
        )

    return f"""
    <div class="card chart-card small-chart">
        <h3>{escape(title)}</h3>
        <div class="legend">
            <span><i class="rx"></i>RX</span>
            <span><i class="tx"></i>TX</span>
            <span class="chart-note">Source: raw usage table, exact selected range</span>
        </div>
        <div class="svg-wrap">
            <svg viewBox="0 0 {w} {h}" role="img" aria-label="{escape(title)}">
                {''.join(grid)}
                {''.join(labels)}
                <line x1="{left}" y1="{top}" x2="{left}" y2="{h-bottom}" class="axis"/>
                <line x1="{left}" y1="{h-bottom}" x2="{w-right}" y2="{h-bottom}" class="axis"/>
                <polyline points="{rx_points}" class="line rx-line"/>
                <polyline points="{tx_points}" class="line tx-line"/>
                {''.join(dot_items)}
                {''.join(x_labels)}
                {''.join(hover_items)}
            </svg>
        </div>
    </div>
    """

def vm_metric_chart_svg(rows, title, series, source_note="", render_zero=False):
    rows = sample_chart_rows(rows)
    """Generic small multi-line chart for one VM metric family."""
    series = list(series or [])
    if not series:
        return ""

    real_max = 0.0
    for row in rows or []:
        for item in series:
            real_max = max(real_max, float(row.get(item["key"], 0) or 0))

    if not rows or (real_max <= 0 and not render_zero):
        return f"""
        <div class="card chart-card small-chart">
            <h3>{escape(title)}</h3>
            <div class="empty">No chart data in this period</div>
        </div>
        """

    # Optional zero-value chart keeps the VM chart grid balanced for metrics
    # where 0 is meaningful, especially healthy Drops / Errors.
    zero_chart = real_max <= 0

    w, h = 860, 240
    left, right, top, bottom = 74, 18, 18, 42
    plot_w = w - left - right
    plot_h = h - top - bottom
    max_v = 1 if zero_chart else nice_ceiling(real_max)

    grid = []
    labels = []
    first_kind = series[0].get("kind", "raw")
    for i in range(5):
        ratio = i / 4
        y = top + plot_h - ratio * plot_h
        value = max_v * ratio
        grid.append(f'<line x1="{left}" y1="{y:.1f}" x2="{w-right}" y2="{y:.1f}" class="grid-line"/>')
        labels.append(f'<text x="8" y="{y+4:.1f}" class="axis-label">{escape(fmt_metric_value(value, first_kind))}</text>')

    x_labels = []
    n = len(rows)
    if n <= 7:
        idxs = list(range(n))
    else:
        idxs = sorted(set([0, n//4, n//2, (3*n)//4, n-1]))
    for idx in idxs:
        x = left + (idx * plot_w / (n - 1)) if n > 1 else left + plot_w / 2
        x_labels.append(f'<text x="{x:.1f}" y="{h-15}" class="x-label" text-anchor="middle">{escape(rows[idx]["label"])}</text>')

    line_items = []
    dot_items = []
    legend_items = []
    hover_items = []
    band_w = plot_w / max(n - 1, 1)

    for sidx, item in enumerate(series):
        key = item["key"]
        cls = item.get("class", f"metric{sidx + 1}")
        points = make_points(rows, key, left, top, plot_w, plot_h, max_v)
        line_items.append(f'<polyline points="{points}" class="line {cls}-line"/>')
        legend_items.append(f'<span><i class="{cls}"></i>{escape(item.get("label", key))}</span>')

        for idx, row in enumerate(rows):
            if float(row.get(key, 0) or 0) <= 0:
                continue
            x, y = point_xy(rows, idx, key, left, top, plot_w, plot_h, max_v)
            dot_items.append(f'<circle cx="{x:.1f}" cy="{y:.1f}" r="2.4" class="dot {cls}-dot"/>')

    for idx, row in enumerate(rows):
        x = left + (idx * plot_w / (n - 1)) if n > 1 else left + plot_w / 2
        hover_x = x - band_w / 2
        hover_w = band_w if n > 1 else plot_w
        parts = [fmt_full(row["bucket"])]
        for item in series:
            parts.append(f'{item.get("label", item["key"])}: {fmt_metric_value(row.get(item["key"], 0), item.get("kind", "raw"))}')
        tooltip = "\n".join(parts)
        hover_items.append(
            f'<rect x="{hover_x:.1f}" y="{top}" width="{hover_w:.1f}" height="{plot_h}" class="hover-zone">'
            f'<title>{escape(tooltip)}</title></rect>'
        )

    note_html = f'<span class="chart-note">{escape(source_note)}</span>' if source_note else ''
    return f"""
    <div class="card chart-card small-chart">
        <h3>{escape(title)}</h3>
        <div class="legend">
            {''.join(legend_items)}
            {note_html}
        </div>
        <div class="svg-wrap">
            <svg viewBox="0 0 {w} {h}" role="img" aria-label="{escape(title)}">
                {''.join(grid)}
                {''.join(labels)}
                <line x1="{left}" y1="{top}" x2="{left}" y2="{h-bottom}" class="axis"/>
                <line x1="{left}" y1="{h-bottom}" x2="{w-right}" y2="{h-bottom}" class="axis"/>
                {''.join(line_items)}
                {''.join(dot_items)}
                {''.join(x_labels)}
                {''.join(hover_items)}
            </svg>
        </div>
    </div>
    """


