        conn.execute("SELECT 1").fetchone()
        current_abuse = safe_int(conn.execute(
            "SELECT COUNT(*) FROM vm_abuse_state WHERE is_abuse=1 AND last_seen>=?",
            (now_ts() - FAST_CURRENT_STALE_SECONDS,),
        ).fetchone()[0], 0)
